ruleContent.content:
$.data
<js>
function cleanChapterText(text) {
  const lines = text.split('\n');
  const filteredLines = lines.filter(line => {
    return !(line.includes('第') && line.includes('章')) && 
           !line.includes('作者：') &&
           !/^\d{4}-\d{2}-\d{2}/.test(line.trim());
  });
  return filteredLines.join('\n');
}

cleanChapterText(result);
</js>

ruleToc.chapterList:
class.chapter-list.1@a<js>

function parseAndFixChapterList(html) {
  // 1. 拆分行
  const lines = html.split('\n').map(l => l.trim()).filter(Boolean);

  if (lines.length === 0) return [];

  // 2. 自动提取基础路径（从第一个链接截取前缀）
  const firstHrefMatch = lines[0].match(/href="([^"]+\/)\d+\.html"/);
  const baseHref = firstHrefMatch ? firstHrefMatch[1] : '';

  // 3. 遍历解析 + 按顺序生成正确 href
  return lines.map((line, index) => {
    // 提取章节名
    const nameMatch = line.match(/<a[^>]+>(.+?)<\/a>/);
    const name = nameMatch ? nameMatch[1].trim() : '';

    // 按顺序生成链接
    const href = `${baseHref}${index + 1}.html`;

    return { href, name };
  });
}
result = parseAndFixChapterList(String(result))
</js>

