(() => {
  let url = result[0]
  let count = 3;
  let num = url?.match(/\/(\d)\.html/)?.[1] || 10000;
  return num <= count ? url : null;
})()

ruleContent.content:
@js:
function player(type, id){
    const url =  "http://www.78497.com/style/js/play.php,";
    const options = {
      body: `type=${type}&id=${id}`,
      headers:{
        "Content-Type":"application/x-www-form-urlencoded",
        "Referer":"http://www.78497.com",
        "User-Agent":"Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/137.0.0.0 Safari/537.36 Edg/137.0.0.0"
     },
    method: "POST"
  }
  return this.java.ajax(url+JSON.stringify(options))
}

const code = result.match(/lkid.*?;(player.*?);/)?.[1];
JSON.parse(eval(code)).url

